		if (capacity == 0) {
			return false;
		}
		if (buffer.size < capacity) {
			return true;
		}
		int worst = heap[0];
		int compared = comparator.compare(row, 0, buffer.rows, worst * buffer.slotCount);
		if (compared == 0) {
			compared = Long.compare(ordinal, buffer.ordinals[worst]);
		}
		return compared < 0;
