	@Override
	public void close() {
		if (closed) {
			return;
		}
		closed = true;
		try {
			input.close();
		} catch (IOException ignored) {
		}
		try {
			if (Files.deleteIfExists(path)) {
				NativeSpillSort.DELETED_RUNS.incrementAndGet();
			}
		} catch (IOException ignored) {
		}
	}
